declare const defaultMessageDataAgentDescription: string;

export { type InconvoResponse, type InconvoToolsOptions, type InconvoUserContext, type SerializeResponse, type UserContextProvider, defaultMessageDataAgentDescription, getDataAgentConnectedDataSummary, inconvoDataAgent, messageDataAgent, startDataAgentConversation };

