    [`get${capitalizedName}DataAgentConnectedDataSummary`]: getDataAgentConnectedDataSummary(options),
    [`start${capitalizedName}DataAgentConversation`]: startDataAgentConversation(options),
    [`message${capitalizedName}DataAgent`]: messageDataAgent(options)
